def test_field_defaults():
    class User(Model):
        name = StringField(default='anon')
        age = IntField(default=0)
    u = User()
    assert u.name == 'anon' and u.age == 0

def test_field_kwargs():
    class User(Model):
        name = StringField()
        age = IntField()
    u = User(name='Alice', age=30)
    assert u.name == 'Alice' and u.age == 30

def test_required_validation():
    class User(Model):
        name = StringField(required=True)
    try:
        User()
        assert False, 'should have raised'
    except ValueError:
        pass

def test_type_check_int():
    class T(Model):
        x = IntField()
    try:
        T(x='not int')
        assert False
    except ValueError:
        pass

def test_type_check_string():
    class T(Model):
        s = StringField()
    try:
        T(s=123)
        assert False
    except ValueError:
        pass

def test_custom_validator():
    class T(Model):
        age = IntField(validator=lambda v: v >= 0)
    try:
        T(age=-1)
        assert False
    except ValueError:
        pass
    T(age=10)
